#include <stdio.h>
#include <string.h>
#define MAX 1500000
char S[MAX];
int main() {
    scanf("%s", S);
    int Q;
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        char op[20], c;
        scanf("%s", op);
        if (strcmp(op, "INSERT_LEFT") == 0) {
            scanf(" %c", &c);
            memmove(S + 1, S, strlen(S));
            S[0] = c;
        } else if (strcmp(op, "INSERT_RIGHT") == 0) {
            scanf(" %c", &c);
            strcat(S, &c);
        } else if (strcmp(op, "INSERT_MIDDLE") == 0) {
            scanf(" %c", &c);
            int mid = strlen(S) / 2;
            memmove(S + mid + 1, S + mid, strlen(S + mid) + 1);
            S[mid] = c;
        } else if (strcmp(op, "DELETE_LEFT") == 0) {
            memmove(S, S + 1, strlen(S));
        } else if (strcmp(op, "DELETE_RIGHT") == 0) {
            S[strlen(S) - 1] = '\0';
        } else if (strcmp(op, "DELETE_MIDDLE") == 0) {
            int mid = strlen(S) / 2;
            memmove(S + mid, S + mid + 1, strlen(S + mid + 1) + 1);
        } else if (strcmp(op, "QUERY") == 0) {
            char q[MAX];
            scanf("%s", q);
            int count = 0;
            for (int j = 0; j <= strlen(S) - strlen(q); j++) {
                if (strncmp(S + j, q, strlen(q)) == 0) {
                    count++;
                }
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

