            char c;
            cin >> c;
            S = c + S;
        } else if (op == "INSERT_RIGHT") {
            char c;
            cin >> c;
            S += c;
        } else if (op == "INSERT_MIDDLE") {
            char c;
            cin >> c;
            int mid = S.length() / 2;
            S.insert(mid, 1, c);
        } else if (op == "DELETE_LEFT") {
            S.erase(0, 1);
        } else if (op == "DELETE_RIGHT") {
            S.pop_back();
        } else if (op == "DELETE_MIDDLE") {
            int mid = S.length() / 2;
            S.erase(mid, 1);
        } else if (op == "QUERY") {
            string q;
            cin >> q;
            int count = 0;
            for (int j = 0; j <= S.length() - q.length(); j++) {
                if (S.substr(j, q.length()) == q) {
                    count++;
                }
            }
            cout << count << endl;
        }
    }
    return 0;
}

