import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String S = sc.next();
        int Q = sc.nextInt();
        for (int i = 0; i < Q; i++) {
            String op = sc.next();
            if (op.equals("INSERT_LEFT")) {
                char c = sc.next().charAt(0);
                S = c + S;
            } else if (op.equals("INSERT_RIGHT")) {
                char c = sc.next().charAt(0);
                S += c;
            } else if (op.equals("INSERT_MIDDLE")) {
                char c = sc.next().charAt(0);
                int mid = S.length() / 2;
                S = S.substring(0, mid) + c + S.substring(mid);
            } else if (op.equals("DELETE_LEFT")) {
                S = S.substring(1);
            } else if (op.equals("DELETE_RIGHT")) {
                S = S.substring(0, S.length() - 1);
            } else if (op.equals("DELETE_MIDDLE")) {
                int mid = S.length() / 2;
                S = S.substring(0, mid) + S.substring(mid + 1);
            } else if (op.equals("QUERY")) {
                String q = sc.next();
                int count = 0;
                for (int j = 0; j <= S.length() - q.length(); j++) {
                    if (S.substring(j, j + q.length()).equals(q)) {
                        count++;
                    }
                }
                System.out.println(count);
            }
        }
    }
}

